#include "hfmTree.h"
#include <stdlib.h>
#include <string.h>
#include <stdio.h>
#include <stdbool.h>

HFMTNode *CreateNode(ElemType element, int w, HFMTNode *lChild, HFMTNode *rChild) {
  HFMTNode *p = (HFMTNode *) malloc(sizeof(HFMTNode));
  if (!p) {
    printf("malloc error, please try again!");
    return NULL;
  }
  p->element = element;
  p->w = w;
  p->lChild = lChild;
  p->rChild = rChild;
  return p;
}

bool IsLeaf(HFMTNode *node) {
  return node != NULL && node->lChild == NULL && node->rChild == NULL;
}

void Clear(HFMTNode *node) {
  if (!node)
    return;
  Clear(node->lChild);
  Clear(node->rChild);
  free(node);
  node = NULL;
}

int DuplicateString(const char *src, char **dst) {
  size_t len = strlen(src);
  *dst = (char *) malloc(len + 1);
  if (*dst == NULL) {
    return ERROR;
  }
  memcpy(*dst, src, len + 1);
  return OK;
}

void ClearHuffmanTree(BinaryTree *tree) {
  if (!tree) {
    return;
  }
  Clear(tree->root);
  free(tree->root);
  tree->root = NULL;
}

void DestroyHuffmanCodes(HFMCodeTable *table) {
  int i;
  if (!table)
    return;
  for (i = 0; i < 256; ++i) {
    free(table->codes[i]);
    table->codes[i] = NULL;
  }
}

HFMTNode *NewNode(ElemType x, HFMTNode *ln, HFMTNode *rn) {
  HFMTNode *p = (HFMTNode *)malloc(sizeof(HFMTNode));
  if (p == NULL) {
    printf("malloc error, please try again!");
    return NULL;
  }
  p->element = x;
  p->lChild = ln;
  p->rChild = rn;
  return p;
}

int CreateHuffmanTree(const ElemType symbols[], const int weights[], int count, BinaryTree *tree) {

}

void MakeTree(BinaryTree *bt, ElemType e, BinaryTree *left, BinaryTree *right) {
  if (bt->root || left == right)
    return;
  bt->root = NewNode(e, left->root, right->root);
  left->root = right->root = NULL;
}



int EncodeText(const char *text, const HFMCodeTable *table, char **encodedBits) {
  size_t totalLen = 0;
  size_t i;
  char *result;

  if (text == NULL || table == NULL || encodedBits == NULL) {
    return ERROR;
  }

  for (i = 0; text[i] != '\0'; ++i) {
    const char *code = table->codes[(unsigned char) text[i]];
    if (code == NULL) {
      return ERROR;
    }
    totalLen += strlen(code);
  }

  result = (char *) malloc(totalLen + 1);
  if (result == NULL) {
    return ERROR;
  }

  result[0] = '\0';
  for (i = 0; text[i] != '\0'; ++i) {
    strcat(result, table->codes[(unsigned char) text[i]]);
  }

  *encodedBits = result;
  return OK;
}

int DecodeBits(const char *bits, const BinaryTree *tree, char **decodedText) {
  size_t bitLen;
  size_t outPos = 0;
  size_t i;
  char *result;
  const HFMTNode *cur;

  if (bits == NULL || tree == NULL || tree->root == NULL || decodedText == NULL) {
    return ERROR;
  }

  bitLen = strlen(bits);
  result = (char *) malloc(bitLen + 2);
  if (result == NULL) {
    return ERROR;
  }

  if (IsLeaf(tree->root)) {
    for (i = 0; i < bitLen; ++i) {
      if (bits[i] != '0') {
        free(result);
        return ERROR;
      }
      result[outPos++] = (char) tree->root->element;
    }
    result[outPos] = '\0';
    *decodedText = result;
    return OK;
  }

  cur = tree->root;
  for (i = 0; i < bitLen; ++i) {
    if (bits[i] == '0') {
      cur = cur->lChild;
    } else if (bits[i] == '1') {
      cur = cur->rChild;
    } else {
      free(result);
      return ERROR;
    }

    if (cur == NULL) {
      free(result);
      return ERROR;
    }

    if (IsLeaf(cur)) {
      result[outPos++] = (char) cur->element;
      cur = tree->root;
    }
  }

  if (cur != tree->root) {
    free(result);
    return ERROR;
  }

  result[outPos] = '\0';
  *decodedText = result;
  return OK;
}

